extension HybridWebViewController: WKScriptMessageHandler {
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let body = message.body as? [String: Any] else { return }
        
        switch message.name {
        case "camera":
            handleCameraRequest(params: body)
        case "notifications":
            handleNotificationRequest(params: body)
        case "purchase":
            handlePurchaseRequest(params: body)
        case "native":
            handleNativeRequest(params: body)
        default:
            break
        }
    }
    
    private func handleCameraRequest(params: [String: Any]) {
        guard let action = params["action"] as? String else { return }
        let callbackId = params["callbackId"] as? String
        
        switch action {
        case "checkPermission":
            let status = AVCaptureDevice.authorizationStatus(for: .video)
            let hasPermission = status == .authorized
            sendCallback(callbackId: callbackId, success: true, data: ["hasPermission": hasPermission])
            
        case "requestPermission":
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                DispatchQueue.main.async {
                    self?.sendCallback(callbackId: callbackId, success: true, data: ["granted": granted])
                }
            }
            
        case "openCamera":
            openCamera(callbackId: callbackId, sourceType: params["sourceType"] as? String)
            
        default:
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Unknown action"])
        }
    }
    
    private func openCamera(callbackId: String?, sourceType: String?) {
        let picker = UIImagePickerController()
        picker.delegate = self
        picker.allowsEditing = params["allowsEditing"] as? Bool ?? false
        
        if sourceType == "photoLibrary" && UIImagePickerController.isSourceTypeAvailable(.photoLibrary) {
            picker.sourceType = .photoLibrary
        } else if UIImagePickerController.isSourceTypeAvailable(.camera) {
            picker.sourceType = .camera
        } else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Camera not available"])
            return
        }
        
        picker.modalPresentationStyle = .fullScreen
        present(picker, animated: true)
        
        objc_setAssociatedObject(picker, "callbackId", callbackId, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
    }
    
    private func handleNotificationRequest(params: [String: Any]) {
        guard let action = params["action"] as? String else { return }
        let callbackId = params["callbackId"] as? String
        
        switch action {
        case "checkPermission":
            UNUserNotificationCenter.current().getNotificationSettings { [weak self] settings in
                DispatchQueue.main.async {
                    let isAuthorized = settings.authorizationStatus == .authorized
                    self?.sendCallback(callbackId: callbackId, success: true, data: ["isAuthorized": isAuthorized])
                }
            }
            
        case "requestPermission":
            UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .sound, .badge]) { [weak self] granted, error in
                DispatchQueue.main.async {
                    if let error = error {
                        self?.sendCallback(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
                    } else {
                        if granted {
                            UIApplication.shared.registerForRemoteNotifications()
                        }
                        self?.sendCallback(callbackId: callbackId, success: true, data: ["granted": granted])
                    }
                }
            }
            
        case "scheduleLocal":
            scheduleLocalNotification(params: params, callbackId: callbackId)
            
        default:
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Unknown action"])
        }
    }
    
    private func scheduleLocalNotification(params: [String: Any], callbackId: String?) {
        let content = UNMutableNotificationContent()
        content.title = params["title"] as? String ?? ""
        content.body = params["body"] as? String ?? ""
        content.sound = .default
        
        let trigger: UNNotificationTrigger?
        if let delay = params["delay"] as? Double {
            trigger = UNTimeIntervalNotificationTrigger(timeInterval: delay, repeats: false)
        } else {
            trigger = nil
        }
        
        let identifier = params["identifier"] as? String ?? UUID().uuidString
        let request = UNNotificationRequest(identifier: identifier, content: content, trigger: trigger)
        
        UNUserNotificationCenter.current().add(request) { [weak self] error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.sendCallback(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
                } else {
                    self?.sendCallback(callbackId: callbackId, success: true, data: ["identifier": identifier])
                }
            }
        }
    }
    
    private func handlePurchaseRequest(params: [String: Any]) {
        guard let action = params["action"] as? String else { return }
        let callbackId = params["callbackId"] as? String
        
        switch action {
        case "canMakePayments":
            let canMake = SKPaymentQueue.canMakePayments()
            sendCallback(callbackId: callbackId, success: true, data: ["canMakePayments": canMake])
            
        case "getProducts":
            if let productIds = params["productIds"] as? [String] {
                fetchProducts(productIds: productIds, callbackId: callbackId)
            } else {
                sendCallback(callbackId: callbackId, success: false, data: ["error": "Missing productIds"])
            }
            
        case "purchase":
            if let productId = params["productId"] as? String {
                purchaseProduct(productId: productId, callbackId: callbackId)
            } else {
                sendCallback(callbackId: callbackId, success: false, data: ["error": "Missing productId"])
            }
            
        case "restorePurchases":
            restorePurchases(callbackId: callbackId)
            
        default:
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Unknown action"])
        }
    }
    
    private func fetchProducts(productIds: [String], callbackId: String?) {
        let request = SKProductsRequest(productIdentifiers: Set(productIds))
