        request.start()
        objc_setAssociatedObject(request, "delegate", delegate, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
    }
    
    private func purchaseProduct(productId: String, callbackId: String?) {
        let request = SKProductsRequest(productIdentifiers: [productId])
        let delegate = PurchaseRequestDelegate(callbackId: callbackId, viewController: self)
        request.delegate = delegate
        request.start()
        objc_setAssociatedObject(request, "delegate", delegate, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
    }
    
    private func restorePurchases(callbackId: String?) {
        let observer = PurchaseObserver(callbackId: callbackId, viewController: self, isRestore: true)
        SKPaymentQueue.default().add(observer)
        SKPaymentQueue.default().restoreCompletedTransactions()
        objc_setAssociatedObject(SKPaymentQueue.default(), "observer", observer, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
    }
    
    private func handleNativeRequest(params: [String: Any]) {
        guard let action = params["action"] as? String else { return }
        let callbackId = params["callbackId"] as? String
        
        switch action {
        case "getDeviceInfo":
            let info: [String: Any] = [
                "model": UIDevice.current.model,
                "systemVersion": UIDevice.current.systemVersion,
                "name": UIDevice.current.name,
                "identifierForVendor": UIDevice.current.identifierForVendor?.uuidString ?? ""
            ]
            sendCallback(callbackId: callbackId, success: true, data: info)
            
        case "openURL":
            if let urlString = params["url"] as? String, let url = URL(string: urlString) {
                UIApplication.shared.open(url) { [weak self] success in
                    self?.sendCallback(callbackId: callbackId, success: success, data: nil)
                }
            } else {
                sendCallback(callbackId: callbackId, success: false, data: ["error": "Invalid URL"])
            }
            
        case "vibrate":
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
            sendCallback(callbackId: callbackId, success: true, data: nil)
            
        case "setStatusBarStyle":
            if let style = params["style"] as? String {
                DispatchQueue.main.async { [weak self] in
                    if style == "light" {
                        self?.setNeedsStatusBarAppearanceUpdate()
                    }
                    self?.sendCallback(callbackId: callbackId, success: true, data: nil)
                }
            }
            
        default:
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Unknown action"])
        }
    }
    
    func sendCallback(callbackId: String?, success: Bool, data: [String: Any]?) {
        guard let callbackId = callbackId else { return }
        
        var response: [String: Any] = [
            "callbackId": callbackId,
            "success": success
        ]
        
        if let data = data {
            response["data"] = data
        }
        
        if let jsonData = try? JSONSerialization.data(withJSONObject: response),
           let jsonString = String(data: jsonData, encoding: .utf8) {
            let script = "window.nativeCallback(\(jsonString));"
            webView.evaluateJavaScript(script)
        }
    }
