        progressView.setProgress(0, animated: false)
        print("Navigation failed: \(error.localizedDescription)")
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        if let url = navigationAction.request.url {
            if url.scheme == "tel" || url.scheme == "mailto" {
                UIApplication.shared.open(url)
                decisionHandler(.cancel)
                return
            }
        }
        decisionHandler(.allow)
    }
}

extension HybridWebViewController: WKUIDelegate {
    
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        present(alert, animated: true)
    }
}

extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        let callbackId = objc_getAssociatedObject(picker, "callbackId") as? String
        
        var image: UIImage?
        if let editedImage = info[.editedImage] as? UIImage {
            image = editedImage
        } else if let originalImage = info[.originalImage] as? UIImage {
            image = originalImage
        }
        
        if let image = image {
            if let imageData = image.jpegData(compressionQuality: 0.8) {
                let base64String = imageData.base64EncodedString()
                sendCallback(callbackId: callbackId, success: true, data: [
                    "image": base64String,
                    "width": image.size.width,
                    "height": image.size.height
                ])
            }
        } else {
            sendCallback(callbackId: callbackId, success: false, data: ["error": "Failed to get image"])
        }
        
        picker.dismiss(animated: true)
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        let callbackId = objc_getAssociatedObject(picker, "callbackId") as? String
        sendCallback(callbackId: callbackId, success: false, data: ["error": "Cancelled"])
        picker.dismiss(animated: true)
    }
}

class ProductRequestDelegate: NSObject, SKProductsRequestDelegate {
    let callbackId: String?
    weak var viewController: HybridWebViewController?
    
    init(callbackId: String?, viewController: HybridWebViewController) {
        self.callbackId = callbackId
        self.viewController = viewController
    }
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        let products = response.products.map { product -> [String: Any] in
            return [
                "productId": product.productIdentifier,
                "title": product.localizedTitle,
                "description": product.localizedDescription,
                "price": product.price.doubleValue,
                "priceLocale": product.priceLocale.currencyCode ?? ""
            ]
        }
        
        viewController?.sendCallback(callbackId: callbackId, success: true, data: ["products": products])
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        viewController?.sendCallback(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
    }
}

class PurchaseRequestDelegate: NSObject, SKProductsRequestDelegate {
    let callbackId: String?
    weak var viewController: HybridWebViewController?
    
    init(callbackId: String?, viewController: HybridWebViewController) {
        self.callbackId = callbackId
        self.viewController = viewController
    }
    
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        guard let product = response.products.first else {
            viewController?.sendCallback(callbackId: callbackId, success: false, data: ["error": "Product not found"])
            return
        }
        
        let payment = SKPayment(product: product)
        let observer = PurchaseObserver(callbackId: callbackId, viewController: viewController, isRestore: false)
        SKPaymentQueue.default().add(observer)
        SKPaymentQueue.default().add(payment)
        objc_setAssociatedObject(SKPaymentQueue.default(), "observer", observer, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        viewController?.sendCallback(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
    }
}

class PurchaseObserver: NSObject, SKPaymentTransactionObserver {
    let callbackId: String?
    weak var viewController: HybridWebViewController?
    let isRestore: Bool
    
    init(callbackId: String?, viewController: HybridWebViewController?, isRestore: Bool) {
        self.callbackId = callbackId
        self.viewController = viewController
        self.isRestore = isRestore
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                handlePurchased(transaction: transaction)
                SKPaymentQueue.default().finishTransaction(transaction)
            case .failed:
                handleFailed(transaction: transaction)
                SKPaymentQueue.default().finishTransaction(transaction)
            case .restored:
                handleRestored(transaction: transaction)
                SKPaymentQueue.default().finishTransaction(transaction)
            case .deferred, .purchasing:
                break
            @unknown default:
                break
            }
        }
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        if isRestore {
            viewController?.sendCallback(callbackId: callbackId, success: true, data: ["restored": true])
            SKPaymentQueue.default().remove(self)
        }
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        if isRestore {
            viewController?.sendCallback(callbackId: callbackId, success: false, data: ["error": error.localizedDescription])
            SKPaymentQueue.default().remove(self)
        }
    }
    
    private func handlePurchased(transaction: SKPaymentTransaction) {
        let data: [String: Any] = [
            "productId": transaction.payment.productIdentifier,
            "transactionId": transaction.transactionIdentifier ?? ""
        ]
        viewController?.sendCallback(callbackId: callbackId, success: true, data: data)
        SKPaymentQueue.default().remove(self)
    }
    
    private func handleFailed(transaction: SKPaymentTransaction) {
        let error = transaction.error as? SKError
        let errorMessage = error?.localizedDescription ?? "Purchase failed"
        viewController?.sendCallback(callbackId: callbackId, success: false, data: ["error": errorMessage])
        SKPaymentQueue.default().remove(self)
    }
    
    private func handleRestored(transaction: SKPaymentTransaction) {
        let data: [String: Any] = [
            "productId": transaction.payment.productIdentifier,
            "transactionId": transaction.transactionIdentifier ?? ""
        ]
        viewController?.sendCallback(callbackId: callbackId, success: true, data: data)
    }
}